import{_ as l,o as r,c as i,ai as n}from"./chunks/framework.ampVZV4B.js";const b=JSON.parse('{"title":"关系型数据库","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/database/relational.md","filePath":"tech-system/database/relational.md"}'),t={name:"tech-system/database/relational.md"};function e(s,a,o,h,g,d){return r(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="关系型数据库" tabindex="-1">关系型数据库 <a class="header-anchor" href="#关系型数据库" aria-label="Permalink to “关系型数据库”">​</a></h1><p>关系型数据库通过表、行、列来组织数据，支持 ACID 事务和复杂查询。是企业应用最常用的数据存储方式。</p><h2 id="数据库基础" tabindex="-1">数据库基础 <a class="header-anchor" href="#数据库基础" aria-label="Permalink to “数据库基础”">​</a></h2><h3 id="acid-特性" tabindex="-1">ACID 特性 <a class="header-anchor" href="#acid-特性" aria-label="Permalink to “ACID 特性”">​</a></h3><ul><li><strong>原子性 (Atomicity)</strong>: 事务要么全部成功、要么全部失败</li><li><strong>一致性 (Consistency)</strong>: 数据始终处于一致状态</li><li><strong>隔离性 (Isolation)</strong>: 事务相互隔离、互不影响</li><li><strong>持久性 (Durability)</strong>: 事务提交后数据永久保存</li></ul><h3 id="关系模型" tabindex="-1">关系模型 <a class="header-anchor" href="#关系模型" aria-label="Permalink to “关系模型”">​</a></h3><ul><li><strong>表</strong>: 行的集合、列代表属性、主键唯一标识</li><li><strong>关系</strong>: 一对一、一对多、多对多、自我关系</li><li><strong>范式</strong>: 第一范式、第二范式、第三范式、BCNF</li></ul><h2 id="常见数据库" tabindex="-1">常见数据库 <a class="header-anchor" href="#常见数据库" aria-label="Permalink to “常见数据库”">​</a></h2><h3 id="mysql" tabindex="-1">MySQL <a class="header-anchor" href="#mysql" aria-label="Permalink to “MySQL”">​</a></h3><ul><li><strong>特性</strong>: 开源、轻量级、LAMP 标准组件</li><li><strong>存储引擎</strong>: InnoDB、MyISAM、性能差异</li><li><strong>版本</strong>: MySQL 5.7、8.0、新特性和改进</li><li><strong>分支</strong>: MariaDB、Percona、优化版本</li></ul><h3 id="postgresql" tabindex="-1">PostgreSQL <a class="header-anchor" href="#postgresql" aria-label="Permalink to “PostgreSQL”">​</a></h3><ul><li><strong>特性</strong>: 功能完整、稳定可靠、高级特性丰富</li><li><strong>扩展</strong>: 全文搜索、JSON、XML、PostGIS</li><li><strong>MVCC</strong>: 多版本并发控制、高并发支持</li><li><strong>性能</strong>: 复杂查询优化、执行计划、索引类型</li></ul><h3 id="其他数据库" tabindex="-1">其他数据库 <a class="header-anchor" href="#其他数据库" aria-label="Permalink to “其他数据库”">​</a></h3><ul><li><strong>Oracle</strong>: 企业级、功能完整、商业支持</li><li><strong>SQL Server</strong>: Windows 集成、Business Intelligence</li><li><strong>SQLite</strong>: 嵌入式、文件本地、轻量级应用</li></ul><h2 id="sql-语言" tabindex="-1">SQL 语言 <a class="header-anchor" href="#sql-语言" aria-label="Permalink to “SQL 语言”">​</a></h2><h3 id="基础查询" tabindex="-1">基础查询 <a class="header-anchor" href="#基础查询" aria-label="Permalink to “基础查询”">​</a></h3><ul><li><strong>SELECT</strong>: 列选择、表达式、DISTINCT、LIMIT</li><li><strong>WHERE</strong>: 条件过滤、组合条件、NULL 检查</li><li><strong>ORDER BY</strong>: 排序字段、升序降序、多列排序</li><li><strong>GROUP BY</strong>: 分组聚合、HAVING 过滤</li></ul><h3 id="高级查询" tabindex="-1">高级查询 <a class="header-anchor" href="#高级查询" aria-label="Permalink to “高级查询”">​</a></h3><ul><li><strong>JOIN</strong>: INNER JOIN、LEFT JOIN、RIGHT JOIN、FULL OUTER JOIN</li><li><strong>子查询</strong>: 标量子查询、行子查询、表子查询</li><li><strong>通用表表达式</strong>: WITH 语句、递归 CTE、复杂查询</li><li><strong>窗口函数</strong>: OVER、PARTITION BY、ROW_NUMBER、RANK</li></ul><h3 id="数据修改" tabindex="-1">数据修改 <a class="header-anchor" href="#数据修改" aria-label="Permalink to “数据修改”">​</a></h3><ul><li><strong>INSERT</strong>: 单行插入、批量插入、INSERT SELECT</li><li><strong>UPDATE</strong>: 条件更新、多列更新、全表更新</li><li><strong>DELETE</strong>: 条件删除、级联删除、删除全表</li></ul><h2 id="索引优化" tabindex="-1">索引优化 <a class="header-anchor" href="#索引优化" aria-label="Permalink to “索引优化”">​</a></h2><h3 id="索引类型" tabindex="-1">索引类型 <a class="header-anchor" href="#索引类型" aria-label="Permalink to “索引类型”">​</a></h3><ul><li><strong>B-Tree 索引</strong>: 默认索引、范围查询、排序快速</li><li><strong>Hash 索引</strong>: 精确匹配、内存表、等值查询</li><li><strong>全文索引</strong>: 文本搜索、模糊查询、倒排索引</li><li><strong>GiST/GIN</strong>: PostgreSQL 专有、复杂查询、自定义类型</li></ul><h3 id="索引优化-1" tabindex="-1">索引优化 <a class="header-anchor" href="#索引优化-1" aria-label="Permalink to “索引优化”">​</a></h3><ul><li><strong>创建策略</strong>: 选择列、复合索引、覆盖索引</li><li><strong>维护</strong>: 索引碎片整理、重建、删除未使用</li><li><strong>监控</strong>: 索引使用情况、慢查询分析、执行计划</li></ul><h3 id="查询优化" tabindex="-1">查询优化 <a class="header-anchor" href="#查询优化" aria-label="Permalink to “查询优化”">​</a></h3><ul><li><strong>执行计划</strong>: EXPLAIN、成本分析、索引使用</li><li><strong>查询改写</strong>: 避免全表扫描、避免函数调用</li><li><strong>统计信息</strong>: 直方图、行数估算、查询优化</li></ul><h2 id="事务处理" tabindex="-1">事务处理 <a class="header-anchor" href="#事务处理" aria-label="Permalink to “事务处理”">​</a></h2><h3 id="隔离级别" tabindex="-1">隔离级别 <a class="header-anchor" href="#隔离级别" aria-label="Permalink to “隔离级别”">​</a></h3><ul><li><strong>Read Uncommitted</strong>: 最低隔离、脏读、可见</li><li><strong>Read Committed</strong>: 防止脏读、幻读可能</li><li><strong>Repeatable Read</strong>: MySQL 默认、可重复读、幻读存在</li><li><strong>Serializable</strong>: 最高隔离、串行化、性能最低</li></ul><h3 id="并发控制" tabindex="-1">并发控制 <a class="header-anchor" href="#并发控制" aria-label="Permalink to “并发控制”">​</a></h3><ul><li><strong>锁机制</strong>: 行锁、表锁、谓词锁、间隙锁</li><li><strong>死锁</strong>: 死锁产生、死锁检测、死锁破除</li><li><strong>MVCC</strong>: 版本控制、快照隔离、读写分离</li></ul><h2 id="数据持久化" tabindex="-1">数据持久化 <a class="header-anchor" href="#数据持久化" aria-label="Permalink to “数据持久化”">​</a></h2><h3 id="wal-write-ahead-logging" tabindex="-1">WAL (Write-Ahead Logging) <a class="header-anchor" href="#wal-write-ahead-logging" aria-label="Permalink to “WAL (Write-Ahead Logging)”">​</a></h3><ul><li><strong>原理</strong>: 先写日志、再写数据、保证持久性</li><li><strong>性能</strong>: 性能权衡、批量提交、同步方式</li></ul><h3 id="检查点" tabindex="-1">检查点 <a class="header-anchor" href="#检查点" aria-label="Permalink to “检查点”">​</a></h3><ul><li><strong>作用</strong>: 数据一致性、恢复时间、磁盘空间</li><li><strong>流程</strong>: Dirty page 刷盘、LSN 记录、日志回收</li></ul><h3 id="恢复机制" tabindex="-1">恢复机制 <a class="header-anchor" href="#恢复机制" aria-label="Permalink to “恢复机制”">​</a></h3><ul><li><strong>崩溃恢复</strong>: 前滚、回滚、两阶段提交</li><li><strong>备份恢复</strong>: 全量备份、增量备份、时间点恢复</li></ul><h2 id="架构与扩展" tabindex="-1">架构与扩展 <a class="header-anchor" href="#架构与扩展" aria-label="Permalink to “架构与扩展”">​</a></h2><h3 id="单机优化" tabindex="-1">单机优化 <a class="header-anchor" href="#单机优化" aria-label="Permalink to “单机优化”">​</a></h3><ul><li><strong>配置参数</strong>: 内存分配、缓存大小、连接数</li><li><strong>存储优化</strong>: SSD、RAID、存储架构</li><li><strong>网络</strong>: 本地连接、跨域连接、带宽限制</li></ul><h3 id="主从复制" tabindex="-1">主从复制 <a class="header-anchor" href="#主从复制" aria-label="Permalink to “主从复制”">​</a></h3><ul><li><strong>同步复制</strong>: 主从同步、延迟控制、一致性保证</li><li><strong>异步复制</strong>: 性能优先、可能不一致、故障恢复</li><li><strong>配置</strong>: Binlog、Masterinfo、Relaylog</li></ul><h3 id="分布式扩展" tabindex="-1">分布式扩展 <a class="header-anchor" href="#分布式扩展" aria-label="Permalink to “分布式扩展”">​</a></h3><ul><li><strong>分库分表</strong>: Sharding Key、一致性 Hash、中间件</li><li><strong>分片策略</strong>: 范围分片、Hash 分片、目录分片</li><li><strong>跨分片查询</strong>: 多片查询、结果聚合、分布式事务</li></ul><h2 id="备份与恢复" tabindex="-1">备份与恢复 <a class="header-anchor" href="#备份与恢复" aria-label="Permalink to “备份与恢复”">​</a></h2><h3 id="备份策略" tabindex="-1">备份策略 <a class="header-anchor" href="#备份策略" aria-label="Permalink to “备份策略”">​</a></h3><ul><li><strong>全量备份</strong>: mysqldump、xtrabackup、物理备份</li><li><strong>增量备份</strong>: Binlog 备份、差异备份、条件备份</li><li><strong>备份验证</strong>: 备份测试、恢复测试、完整性检查</li></ul><h3 id="灾难恢复" tabindex="-1">灾难恢复 <a class="header-anchor" href="#灾难恢复" aria-label="Permalink to “灾难恢复”">​</a></h3><ul><li><strong>RTO</strong>: 恢复时间目标、快速恢复机制</li><li><strong>RPO</strong>: 恢复点目标、数据丢失最小化</li><li><strong>故障转移</strong>: 自动故障转移、手动介入、验证机制</li></ul><h2 id="监控与维护" tabindex="-1">监控与维护 <a class="header-anchor" href="#监控与维护" aria-label="Permalink to “监控与维护”">​</a></h2><h3 id="性能监控" tabindex="-1">性能监控 <a class="header-anchor" href="#性能监控" aria-label="Permalink to “性能监控”">​</a></h3><ul><li><strong>关键指标</strong>: QPS、TPS、响应时间、慢查询</li><li><strong>监控工具</strong>: Prometheus、Grafana、MySQL Exporter</li><li><strong>告警阈值</strong>: CPU、内存、磁盘、连接数</li></ul><h3 id="日志分析" tabindex="-1">日志分析 <a class="header-anchor" href="#日志分析" aria-label="Permalink to “日志分析”">​</a></h3><ul><li><strong>慢查询日志</strong>: 查询时间、IO 操作、优化建议</li><li><strong>错误日志</strong>: 启动错误、运行时错误、告警信息</li><li><strong>通用日志</strong>: 所有操作、调试用、开销大</li></ul><h2 id="应用开发" tabindex="-1">应用开发 <a class="header-anchor" href="#应用开发" aria-label="Permalink to “应用开发”">​</a></h2><h3 id="orm-框架" tabindex="-1">ORM 框架 <a class="header-anchor" href="#orm-框架" aria-label="Permalink to “ORM 框架”">​</a></h3><ul><li><strong>SQL</strong>: 编写映射、自动生成、类型安全</li><li><strong>操作</strong>: 查询、创建、更新、删除</li><li><strong>关联</strong>: 一对多、多对多关系、级联操作</li><li><strong>缓存</strong>: N+1 问题、预加载、查询优化</li></ul><h3 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>连接管理</strong>: 连接池、连接复用、超时设置</li><li><strong>SQL 编写</strong>: SQL 注入防护、参数化查询、事务处理</li><li><strong>性能</strong>: 索引使用、查询优化、批量操作</li><li><strong>可维护性</strong>: 命名规范、文档完整、版本控制</li></ul>',62)])])}const m=l(t,[["render",e]]);export{b as __pageData,m as default};
